@code {
    private RegistrationModel model = new();
    private EditContext editContext = null!;
    private ValidationMessageStore serverMessageStore = null!;
    private bool submitted;
    private bool isSubmitting;

    protected override void OnInitialized()
    {
        editContext = new EditContext(model);
        serverMessageStore = new ValidationMessageStore(editContext);

        // Clear server-side errors when the user modifies a field
        editContext.OnFieldChanged += (_, args) =>
        {
            serverMessageStore.Clear(args.FieldIdentifier);
            editContext.NotifyValidationStateChanged();
        };
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;

        try
        {
            serverMessageStore.Clear();

            var errors = await Registration.ValidateAsync(model);

            if (errors.Count > 0)
            {
                foreach (var (field, message) in errors)
                {
                    serverMessageStore.Add(editContext.Field(field), message);
                }
                editContext.NotifyValidationStateChanged();
                return;
            }

            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

